INSERT INTO sections (id, chip, title, subtitle, extra_json) VALUES
('hero', NULL, 'Профессиональное <span class="mark mark--red">продвижение</span> бизнеса на <span class="avito"><img src="assets/logo-avito.svg" alt="" class="avito__icon">Avito</span>', NULL, '{"cta_text":"Смотреть кейсы","cta_href":"#case"}'),
('problems', 'Проблемы, которые мы решаем', 'Деньги уходят, <span class="mark mark--blue">а заявок нет?</span><br>Знакомо. Мы с этим справляемся.', 'Сейчас Ваш канал авито генерирует только 5-10% лидов из-за следующих проблем:', '{"bubble_text1":"<strong>Если у Вас есть хотя бы один пункт</strong> — давайте знакомиться.","bubble_text2":"Мы берем эти проблемы на себя, а Вы получаете стабильный поток клиентов.","bubble_img":"assets/problems-group.png"}'),
('process', 'Как мы продвигаем на Авито?', 'От Вашей заявки до первых клиентов —<br>всего 5 дней. Работаем четко по плану', NULL, '{}'),
('maintenance', 'Ведение', 'Мы постоянно работаем над Вашим проектом, чтобы реклама приносила <span class="mark mark--red">высокий и стабильный результат</span>', NULL, '{}'),
('results', 'Что вы получаете?', 'Наши партнеры получают реальные <span class="mark mark--red">результаты</span>', NULL, '{"description":"Мы нацелены на сотрудничество которое будет успешным с обеих сторон. Придерживаемся стратегии win-win со всеми нашими партнерами.","feature_label":"прирост лидов на проектах"}'),
('cta1', NULL, 'Запишитесь на бесплатный разбор стратегии и получайте больше клиентов с <span class="avito avito--light"><img src="assets/logo-avito.svg" alt="">Avito</span>', NULL, '{"button_text":"Записаться","success_text":"Спасибо! Заявка отправлена, мы свяжемся с вами в ближайшее время."}'),
('team', 'О команде', 'Профессионалы с глубокой экспертизой,<br>нацеленные на высокий результат в проекте', NULL, '{}'),
('certs', 'Сертификаты', 'Ваш аккаунт в безопасности.<br>Мы — официальный партнер <span class="avito"><img src="assets/logo-avito.svg" alt="">Avito</span>', NULL, '{"description":"Мы нацелены на сотрудничество которое будет успешным. Этот статус дает нам доступ к прямой поддержке Avito и новым инструментам. Для вас это значит: максимальная эффективность и полная защита от блокировок."}'),
('pricing', 'Тарифы на продвижение', 'Выберите вариант сотрудничества,<br>который подходит именно вам', NULL, '{}'),
('benefits', 'Почему мы?', 'Почему 9 из 10 клиентов остаются с нами на долгий срок?', NULL, '{}'),
('cases', 'Кейсы продвижения на авито', 'Нам доверяют бизнес в разных нишах', NULL, '{"all_cases_link":"https://lead-key.ru/case","all_cases_text":"Смотреть все кейсы"}'),
('cta2', NULL, 'Хотите получить такие же результаты?', 'Запишитесь на бесплатный разбор стратегии в <span class="avito avito--light"><img src="assets/logo-avito.svg" alt="">Avito</span>', '{"button_text":"Записаться","success_text":"Спасибо! Заявка отправлена, мы свяжемся с вами в ближайшее время."}'),
('reviews', 'Отзывы', 'Реальные отзывы наших клиентов', NULL, '{}'),
('faq', 'Часто задаваемые вопросы', 'Собрали главное, что важно знать перед стартом совместной работы', NULL, '{}'),
('final_cta', NULL, 'Готовы получать заявки с <span class="avito"><img src="assets/logo-avito.svg" alt="">Avito</span>?', 'Оставьте заявку и получите бесплатный аудит Вашего аккаунта с планом по увеличению заявок.', '{"button_text":"Получить план продвижения","success_text":"Спасибо! Заявка отправлена, мы свяжемся с вами в ближайшее время."}');
