INSERT INTO benefits (number, title, text, icon_svg, color, sort_order) VALUES
('01', 'Нацелены на реальные результаты в Вашем бизнесе', 'Не просто настраиваем рекламу, а комплексно подходим к работе над проектом: анализируем всю воронку продаж, от сообщения на Авито до закрытия сделки менеджером.', '<circle cx="12" cy="12" r="9"/><circle cx="12" cy="12" r="4"/><path d="M12 1v3M12 20v3M1 12h3M20 12h3"/>', 'blue', 1),
('02', 'Команда, а не один человек', 'Над проектом работает 4 специалиста одновременно, каждый эксперт в своей области.', '<circle cx="9" cy="8" r="3"/><circle cx="17" cy="9" r="2.5"/><path d="M3 19c0-3 2.7-5 6-5s6 2 6 5M15 18c0-2 1.5-3.5 3.5-3.5S22 16 22 18"/>', 'purple', 2),
('03', 'Всегда на связи, не пропадаем', 'Отвечаем в чате в течение 40 минут в рабочее время, в случае форс-мажора оперативно реагируем даже в выходные.', '<path d="M21 11.5a8.4 8.4 0 01-9 8.4L4 21l1.1-4A8.4 8.4 0 1121 11.5z"/>', 'blue', 3),
('04', 'Концепция Win-Win', 'Ключевая цель работы — ваши продажи, а не просто красивая статистика.', '<path d="M8 13l3 3 8-8M3 12l3 3M11 9l5-5"/>', 'purple', 4);
