INSERT INTO reviews (type, name, source, text, video_url, video_path, link, color, sort_order) VALUES
('text', 'Сергей', 'Отзыв из WhatsApp', 'В начале своего нового профессионального пути я вел авито сам, но понимал, что есть какие-то секреты в ведении бизнеса на авито. Хотелось оптимизировать свои финансовые затраты на рекламе, что есть такая профессия — авитолог. Благо судьба свела с вами, Султан. В начале нашего сотрудничества у меня не было возможности погрузиться во все тонкости продвижения на авито, я можно сказать доверил вопрос продвижения незнакомому человеку, но результат не завтавил себя ждать.', NULL, NULL, 'https://lead-key.ru/#reviews', 'green', 1),
('text', 'Михаил', 'Отзыв из WhatsApp', 'Александр, добрый день. Приятно удивлен трафиком людей. Честно прям тяжело уже становится все обрабатывать. Качество их более менее.', NULL, NULL, 'https://lead-key.ru/#reviews', 'blue', 2),
('text', 'GlassTemp', 'Отзыв с Авито', 'Спасибо за профессионально выполненную работу по продвижению и оформлению профиля', NULL, NULL, 'https://lead-key.ru/#reviews', 'purple', 3),
('text', 'Владислав', 'Отзыв из WhatsApp', 'Все очень круто, работал с многими, но только вы смогли наладить поток лидов, будем и дальше продолжать работать', NULL, NULL, 'https://lead-key.ru/#reviews', 'green', 4);
INSERT INTO faq_items (question, answer, sort_order) VALUES
('Кто такой авитолог?', 'Авитолог — это специалист по продвижению товаров или услуг на платформе Avito (Авито). Он настраивает платные рекламные кампании, создает продающие объявления с привлекательными заголовками, проводит глубокое сравнение предложений конкурентов и управляет бюджетом для достижения главной цели - привлечения внимания потенциальных покупателей и роста продаж. Этот эксперт отлично знает алгоритмы Авито, понимает, какие факторы влияют на видимость объявлений и как за счет этого увеличивают охват без лишних затрат.', 1),
('Какие услуги предоставляет авитолог?', 'Комплексное продвижение на Авито включает аудит ниши, разработку стратегии, создание и размещение карточки товара, запуск и регулярное сопровождение рекламы. Если карточка уже есть, проводится оптимизация контента с использованием качественных фото, элементов инфографики. Цель - улучшить позиции в выдаче Авито и повысить количество просмотров. Ваша задача — своевременно обрабатывать входящие обращения от пользователей.', 2),
('Сколько времени занимает подготовка и запуск проекта с нуля?', 'Весь процесс занимает до 5 дней — от момента, когда вы обратились к нам, до получения первых откликов. Конкретные сроки напрямую зависят от объема продвигаемых товаров или услуг и вашей оперативности в передаче нам исходных данных. Мы используем проверенные решения digital-маркетинга и полностью берем на себя составление подробного плана продвижения на Авито, подготовку материалов (в том числе фотографий), описаний и обложек. Это позволяет запустить продвижение в короткий срок, получить эффект уже за первую неделю сотрудничества.', 3),
('Сколько стоят услуги продвижения и от чего зависит цена?', 'От 25 тысяч рублей в месяц. Итоговая сумма формируется исходя из количества объявлений, числа продвигаемых продуктов и выбранного тарифа.', 4),
('Можно оплачивать работу процентом от продаж, или только фиксированная оплата?', 'У нас фиксированная тарифная сетка с ежемесячной оплатой.', 5),
('Какой минимальный рекламный бюджет (на платное продвижение внутри Авито) нужно закладывать?', 'Начать можно с рекламного бюджета от 20 тысяч рублей. Ведение кампании — от 25 тысяч рублей в месяц: итоговая сумма зависит от количества объявлений и числа продвигаемых услуг.', 6),
('Через какое время после старта появляются первые заявки и когда ждать стабильных результатов?', 'Примерно через 1–3 дня после старта начинают приходить первые отклики, а со 2-3-й недели размещения идёт уже стабильный поток обращений. Мы ежедневно отслеживаем статистику, чтобы точно оценить результаты, которые дает продвижение и при необходимости корректируем само объявление на Авито.', 7),
('Какие гарантии вы даете?', 'Мы работаем по договору, прописываем все условия и обязанности сторон. Нам важно обеспечить реальный результат для вашего бизнеса в виде увеличения числа сделок. Вы регулярно получаете понятные отчеты с основными показателями по трафику и продажам.', 8),
('Как технически происходит настройка рекламы: через кабинет Авито или сторонние инструменты?', 'Мы запускаем кампании именно в кабинете Авито: настраиваем оптимальный бюджет, таргетинг и работу ИИ‑алгоритмов площадки. Дополнительно подключаем автозагрузку объявлений и обновление через интеграции (Excel/XML, API или специализированные сервисы), чтобы они размещались автоматически и актуализировались без ручной рутины. Задействуем также системы аналитики и внешние сервисы. Они помогают глубже изучать поведение покупателей, видеть статистику запросов и активности, отслеживать просмотры, звонки и чаты по каждому объявлению. За счет регулярного анализа мы быстрее замечаем ошибки в оформлении и настройках, тестируем форматы и применяем методы улучшения, чтобы было больше просмотров товара.', 9),
('Можно подключить CRM-систему к аккаунту Авито для удобного учета заявок?', 'Есть прямые интеграции с AmoCRM и Bitrix24. Схему учёта входящих запросов обсуждаем на этапе запуска проекта — выстраиваем понятную воронку от первого контакта на Авито до сделки, чтобы работа с клиентами была удобной для вашей команды.', 10),
('Подойдет Авито для моей ниши? С какими категориями товаров и услуг вы работаете?', 'Продвигаем бизнес в разных сферах: оборудование, монтаж кровли, кадастр, благоустройство территорий, демонтаж зданий, сантехника, теплицы и другое. В каждом проекте адаптируем продвижение на Авито с учетом конкуренции, чтобы получать максимум заказов с площадки.', 11),
('Вы работаете только в моем регионе или по всей России? Есть ограничения по географии?', 'Мы продвигаем проекты по всей РФ. Среди наших кейсов есть компании из Москвы и других районов. Настраиваем показы, исходя из ваших задач — на один город, регион или несколько регионов сразу.', 12),
('Можно эффективно продвигать сразу несколько категорий товаров или услуг в рамках одного аккаунта?', 'Можно начать с одного аккаунта и разместить несколько предложений на Авито, чтобы собрать первичную статистику и протестировать спрос. В дальнейшем, когда данных станет больше, мы может быть предложим разделить направления на отдельные профили для более точной настройки объявлений.', 13),
('Что делать, если конкуренты демпингуют (ставят цену ниже рыночной) и перебивают мои объявления?', 'Сначала нужно проверить, насколько ваша ценовая политика соответствуют рынку. Для этого мы проводим конкурентную разведку и анализируем предложения на Авито. Затем важно выстроить позиционирование бренда: подчеркнуть преимущества вашего предложения, выделить главные отличия, создать уникальный оффер и описание. Все это повысит вашу видимость среди множества других продавцов. У пользователей должно быть четкое представление о ценности предложения.', 14),
('Как вы анализируете эффективность продвижения и понимаете, что стратегия работает?', 'Мы отслеживаем всю воронку (показы, клики, обращения людей). На основе этих данных оптимизируем кампании, снижаем стоимость лида за счет более точных настроек. Формируем для вас прозрачную отчетность.', 15),
('Можно самому завести магазин на Авито, а потом передать его вам на ведение?', 'Да, мы работаем и с уже оформленными профилями на Авито. Анализируем ваше объявление, дорабатываем визуал и тексты, настраиваем и ведем кампании, чтобы увеличить количество целевых заявок.', 16),
('Как отзывы, рейтинг и документы (ИНН, ОГРН) влияют на доверие аудитории?', 'Наличие подтвержденных документов (особенно если вы ООО или ИП) повышают доверие целевой аудитории. Пользователи чаще совершают покупку или звонок в таких случаях. Отзывы и оперативные ответы на сообщения - хороший способ увеличить конверсию. Они помогают клиентам сделать выбор в вашу пользу, когда они ищут надежного подрядчика.', 17);
